function lngLatToVec3(lng, lat, r) {
  var phi   = (90.0 - lat) * Math.PI / 180.0;
  var theta = (lng + 180.0) * Math.PI / 180.0;
  return [
    r * Math.sin(phi) * Math.sin(theta),
    r * Math.cos(phi),
    r * Math.sin(phi) * Math.cos(theta)
  ];
}

function createSeamFixedSphere(segments) {
  var seg = segments || 64;
  var positions = [];
  var normals = [];
  var uvs = [];
  var indices = [];

  for (var y = 0; y <= seg; y++) {
    for (var x = 0; x <= seg; x++) {
      var u = x / seg;
      var v = y / seg;
      var theta = u * 2.0 * Math.PI;
      var phi   = v * Math.PI;
      var sinPhi = Math.sin(phi);
      var cosPhi = Math.cos(phi);
      var sinTheta = Math.sin(theta);
      var cosTheta = Math.cos(theta);
      var nx = sinPhi * sinTheta;
      var ny = cosPhi;
      var nz = sinPhi * cosTheta;
      positions.push(nx, ny, nz);
      normals.push(nx, ny, nz);
      uvs.push(u, v);
    }
  }

  for (var y2 = 0; y2 < seg; y2++) {
    for (var x2 = 0; x2 < seg; x2++) {
      var a = y2 * (seg + 1) + x2;
      var b = a + 1;
      var c = a + (seg + 1);
      var d = c + 1;
      indices.push(a, c, b);
      indices.push(b, c, d);
    }
  }

  return {
    positions: new Float32Array(positions),
    normals: new Float32Array(normals),
    uvs: new Float32Array(uvs),
    indices: new Uint32Array(indices)
  };
}

