var globeFS = '#version 300 es\nprecision highp float;\nin vec3 vNorm;\nin vec3 vPos;\nin vec2 vUV;\nuniform vec3 light;\nuniform sampler2D uEarthTex;\nuniform float uTexLoaded;\nuniform float uUVFlip;\nout vec4 fragColor;\nvoid main(){\n  vec3 n   = normalize(vNorm);\n  vec3 l   = normalize(light - vPos);\n  float d  = max(dot(n, l), 0.0);\n  vec2 uv = vUV;\n  if (uUVFlip > 0.5) { uv.y = 1.0 - uv.y; }\n  vec3 texCol = texture(uEarthTex, uv).rgb;\n  float lat = degrees(asin(clamp(n.y,-1.0,1.0)));\n  float lon = degrees(atan(n.x, n.z));\n  float grid = step(0.97, abs(sin(lat*3.14159/10.0))) + step(0.97, abs(sin(lon*3.14159/10.0)));\n  vec3 ocean = vec3(0.05, 0.12, 0.25);\n  vec3 land  = vec3(0.10, 0.22, 0.18);\n  vec3 procCol = mix(ocean, land, clamp(grid*0.3, 0.0, 1.0));\n  vec3 base = mix(procCol, texCol, uTexLoaded);\n  float rim  = pow(1.0 - max(dot(n, normalize(-vPos)), 0.0), 3.0);\n  vec3 col   = base * (0.2 + 0.8 * d) + vec3(0.15, 0.25, 0.5) * rim * 0.3;\n  fragColor  = vec4(col, 1.0);\n}\n';
s.globeProg = ctx.utils.createProgram(globeVS, globeFS);
