var atmoVS = '#version 300 es\nlayout(location=0) in vec2 aPos;\nout vec2 vUV;\nvoid main(){\n  vUV = aPos * 0.5 + 0.5;\n  gl_Position = vec4(aPos, 0.0, 1.0);\n}\n';

var atmoFS = '#version 300 es\nprecision highp float;\nin vec2 vUV;\nout vec4 fragColor;\nuniform sampler2D uSceneColor;\nuniform sampler2D uSceneDepth;\nuniform mat4 uInvVP;\nuniform vec3 uCamPos;\nuniform vec3 uSunDir;\nuniform float uTime;\nuniform float uAtmoIntensity;\nuniform float uSunIntensity;\nuniform float uAtmoEnabled;\nuniform float uGlobeR;\nuniform float uGlobeScale;\nuniform float uNear;\nuniform float uFar;\n#define PI 3.14159265359\n#define NUM_SAMPLES 16\n#define NUM_LIGHT_SAMPLES 8\nvec2 raySphere(vec3 ro, vec3 rd, float radius) {\n  float b = dot(ro, rd);\n  float c = dot(ro, ro) - radius * radius;\n  float disc = b * b - c;\n  if (disc < 0.0) return vec2(1e20, -1e20);\n  float sq = sqrt(disc);\n  return vec2(-b - sq, -b + sq);\n}\nfloat linearizeDepth(float d) {\n  return 2.0 * uNear * uFar / (uFar + uNear - (2.0 * d - 1.0) * (uFar - uNear));\n}\nvoid main() {\n  vec4 sceneCol = texture(uSceneColor, vUV);\n  float depthSample = texture(uSceneDepth, vUV).r;\n  if (uAtmoEnabled < 0.5) {\n    fragColor = vec4(sceneCol.rgb, 1.0);\n    return;\n  }\n  vec2 ndc = vUV * 2.0 - 1.0;\n  vec4 clipNear = vec4(ndc, -1.0, 1.0);\n  vec4 clipFar  = vec4(ndc,  1.0, 1.0);\n  vec4 wNear = uInvVP * clipNear; wNear /= wNear.w;\n  vec4 wFar  = uInvVP * clipFar;  wFar  /= wFar.w;\n  vec3 ray = normalize(wFar.xyz - wNear.xyz);\n  float sceneDepthWorld = 1e20;\n  if (depthSample < 0.9999) {\n    sceneDepthWorld = linearizeDepth(depthSample);\n  }\n  float planetR = uGlobeR * uGlobeScale;\n  float atmoR = planetR * 1.12;\n  float scaleH = (atmoR - planetR) * 0.25;\n  vec3 betaR = vec3(0.08, 0.20, 0.50) * uAtmoIntensity;\n  vec2 atmoHit = raySphere(uCamPos, ray, atmoR);\n  if (atmoHit.x > atmoHit.y) {\n    fragColor = vec4(sceneCol.rgb, 1.0);\n    return;\n  }\n  vec2 planetHit = raySphere(uCamPos, ray, planetR);\n  float tStart = max(atmoHit.x, 0.0);\n  float tEnd = atmoHit.y;\n  if (planetHit.x > 0.0 && planetHit.x < planetHit.y) {\n    tEnd = min(tEnd, planetHit.x);\n  }\n  tEnd = min(tEnd, sceneDepthWorld);\n  if (tStart >= tEnd) {\n    fragColor = vec4(sceneCol.rgb, 1.0);\n    return;\n  }\n  float cosTheta = dot(ray, uSunDir);\n  float phase = 0.75 * (1.0 + cosTheta * cosTheta);\n  float stepLen = (tEnd - tStart) / float(NUM_SAMPLES);\n  vec3 totalScatter = vec3(0.0);\n  float opticalDepthView = 0.0;\n  for (int i = 0; i < NUM_SAMPLES; i++) {\n    vec3 P = uCamPos + ray * (tStart + (float(i) + 0.5) * stepLen);\n    float h = max(0.0, length(P) - planetR);\n    float localDensity = exp(-h / scaleH);\n    opticalDepthView += localDensity * stepLen;\n    vec2 sunHit = raySphere(P, uSunDir, atmoR);\n    float sunDist = max(sunHit.y, 0.0);\n    float sunStepLen = sunDist / float(NUM_LIGHT_SAMPLES);\n    float opticalDepthSun = 0.0;\n    bool hitPlanet = false;\n    for (int j = 0; j < NUM_LIGHT_SAMPLES; j++) {\n      vec3 S = P + uSunDir * ((float(j) + 0.5) * sunStepLen);\n      float sh = length(S) - planetR;\n      if (sh < 0.0) { hitPlanet = true; break; }\n      opticalDepthSun += exp(-sh / scaleH) * sunStepLen;\n    }\n    if (hitPlanet) continue;\n    vec3 tau = betaR * (opticalDepthView + opticalDepthSun);\n    vec3 attenuation = exp(-tau);\n    totalScatter += localDensity * attenuation * stepLen;\n  }\n  vec3 atmo = totalScatter * betaR * phase * uSunIntensity;\n  vec3 final_col = sceneCol.rgb + atmo;\n  final_col = final_col / (final_col + 1.0);\n  final_col = pow(final_col, vec3(1.0/2.2));\n  fragColor = vec4(final_col, 1.0);\n}\n';

s.atmoProg = ctx.utils.createProgram(atmoVS, atmoFS);
s.atmoLocs = {
  uSceneColor:   gl.getUniformLocation(s.atmoProg, 'uSceneColor'),
  uSceneDepth:   gl.getUniformLocation(s.atmoProg, 'uSceneDepth'),
  uInvVP:        gl.getUniformLocation(s.atmoProg, 'uInvVP'),
  uCamPos:       gl.getUniformLocation(s.atmoProg, 'uCamPos'),
  uSunDir:       gl.getUniformLocation(s.atmoProg, 'uSunDir'),
  uTime:         gl.getUniformLocation(s.atmoProg, 'uTime'),
  uAtmoIntensity:gl.getUniformLocation(s.atmoProg, 'uAtmoIntensity'),
  uSunIntensity: gl.getUniformLocation(s.atmoProg, 'uSunIntensity'),
  uAtmoEnabled:  gl.getUniformLocation(s.atmoProg, 'uAtmoEnabled'),
  uGlobeR:       gl.getUniformLocation(s.atmoProg, 'uGlobeR'),
  uGlobeScale:   gl.getUniformLocation(s.atmoProg, 'uGlobeScale'),
  uNear:         gl.getUniformLocation(s.atmoProg, 'uNear'),
  uFar:          gl.getUniformLocation(s.atmoProg, 'uFar'),
};

function parseCSV(text) {
  var lines = text.split('\n');
  var rows = [];
  for (var i = 1; i < lines.length; i++) {
    var parts = lines[i].split(',');
    if (parts.length < 5) continue;
    var val = parseFloat(parts[3]);
    if (!val || val <= 0) continue;
    rows.push({ year: parts[0], exporter: parts[1], importer: parts[2], value: val });
  }
  return rows;
}

function getRegionColor(country) {
  var ASIA = ['China','Japan','South Korea','India','Singapore','Vietnam','Thailand',
    'Indonesia','Malaysia','Philippines','Taiwan','Cambodia','Myanmar','Laos',
    'Bangladesh','Sri Lanka','Pakistan','Nepal','Bhutan','Maldives','Brunei','Mongolia','North Korea'];
  var AMERICAS = ['United States of America','Canada','Mexico','Brazil','Argentina','Chile',
    'Colombia','Peru','Venezuela','Ecuador','Bolivia','Paraguay','Uruguay','Guyana','Suriname',
    'Cuba','Dominican Republic','Jamaica','Trinidad and Tobago','Bahamas','Haiti','Barbados',
    'Guatemala','Honduras','El Salvador','Nicaragua','Costa Rica','Panama',
    'Antigua & Barbuda','Dominica','Grenada','St. Lucia','St. Vincent and the Grenadines',
    'St. Kitts and Nevis','Belize','Samoa','Tonga','Fiji'];
  var EUROPE = ['Germany','United Kingdom','France','Netherlands','Belgium','Italy','Spain',
    'Russia','Switzerland','Sweden','Norway','Denmark','Finland','Poland','Austria','Ireland',
    'Portugal','Greece','Czech Republic','Romania','Hungary','Ukraine','Belarus','Moldova',
    'Lithuania','Latvia','Estonia','Cyprus','Malta','Iceland','Luxembourg','Slovakia',
    'Slovenia','Croatia','Bulgaria','Albania','Montenegro','Kosovo','Macedonia',
    'Bosnia and Herzegovina','Serbia','Andorra','Liechtenstein','Monaco','San Marino','Yugoslavia'];
  var MIDEAST = ['Saudi Arabia','United Arab Emirates','Qatar','Kuwait','Bahrain','Oman',
    'Iraq','Iran','Turkey','Israel','Lebanon','Jordan','Syria','Yemen','Afghanistan',
    'Georgia','Armenia','Azerbaijan','Kazakhstan','Uzbekistan','Turkmenistan','Tajikistan','Kyrgyzstan'];
  if (ASIA.indexOf(country) >= 0) return [0.2, 0.8, 1.0];
  if (AMERICAS.indexOf(country) >= 0) return [0.4, 0.9, 0.5];
  if (EUROPE.indexOf(country) >= 0) return [0.9, 0.7, 0.3];
  if (MIDEAST.indexOf(country) >= 0) return [0.8, 0.4, 1.0];
  return [1.0, 0.5, 0.4];
}

s._buildScene = function(ctx) {
  var gl2 = ctx.gl;
  var CURVE_SEGS = 40;
  var VERTS = CURVE_SEGS + 1;

  var raw = s.tradeData;
  var laneMap = {};
  for (var ri2 = 0; ri2 < raw.length; ri2++) {
    var r = raw[ri2];
    var key = r.exporter + '|' + r.importer;
    if (!laneMap[key]) laneMap[key] = { count: 0, value: 0, exporter: r.exporter, importer: r.importer };
    laneMap[key].count++;
    laneMap[key].value += r.value;
  }

  var lanes = Object.values(laneMap)
    .filter(function(l) {
      return COUNTRY_COORDS[l.exporter] && COUNTRY_COORDS[l.importer] && l.exporter !== l.importer;
    })
    .sort(function(a, b) { return b.value - a.value; })
    .slice(0, 250);

  if (lanes.length === 0) { s.builtScene = true; s.routes = []; return; }

  var countrySet = {};
  for (var li = 0; li < lanes.length; li++) {
    var l = lanes[li];
    countrySet[l.exporter] = (countrySet[l.exporter] || 0) + l.value;
    countrySet[l.importer] = (countrySet[l.importer] || 0) + l.value;
  }

  var surfaceR = GLOBE_R * 1.005;
  var totalVerts = lanes.length * VERTS;
  var posArr   = new Float32Array(totalVerts * 3);
  var colArr   = new Float32Array(totalVerts * 3);
  var alphaArr = new Float32Array(totalVerts);
  var routes   = [];

  for (var ri = 0; ri < lanes.length; ri++) {
    var lane  = lanes[ri];
    var oCoord = COUNTRY_COORDS[lane.exporter];
    var dCoord = COUNTRY_COORDS[lane.importer];
    var p0 = lngLatToVec3(oCoord[0], oCoord[1], surfaceR);
    var p1 = lngLatToVec3(dCoord[0], dCoord[1], surfaceR);

    var mx = (p0[0]+p1[0])*0.5;
    var my = (p0[1]+p1[1])*0.5;
    var mz = (p0[2]+p1[2])*0.5;
    var mLen = Math.sqrt(mx*mx+my*my+mz*mz) || 1;
    var arcH = GLOBE_R * (0.35 + Math.min(0.60, lane.value / 500000 * 0.25));
    var ctrl = [mx/mLen*(surfaceR+arcH), my/mLen*(surfaceR+arcH), mz/mLen*(surfaceR+arcH)];

    var col = getRegionColor(lane.exporter);
    var startIdx = ri * VERTS;
    for (var i = 0; i < VERTS; i++) {
      var bt = i / (VERTS - 1);
      var mt2 = 1.0 - bt;
      var bx = mt2*mt2*p0[0] + 2*mt2*bt*ctrl[0] + bt*bt*p1[0];
      var by = mt2*mt2*p0[1] + 2*mt2*bt*ctrl[1] + bt*bt*p1[1];
      var bz = mt2*mt2*p0[2] + 2*mt2*bt*ctrl[2] + bt*bt*p1[2];
      var base = (startIdx + i) * 3;
      posArr[base]   = bx;
      posArr[base+1] = by;
      posArr[base+2] = bz;
      colArr[base]   = col[0];
      colArr[base+1] = col[1];
      colArr[base+2] = col[2];
      alphaArr[startIdx + i] = 0.08;
    }

    routes.push({
      startIdx: startIdx, p0: p0, p1: p1, ctrl: ctrl, col: col,
      value: lane.value,
      speed: 0.05 + Math.random() * 0.10,
      phase: Math.random() * Math.PI * 2,
    });
  }

  // 라인 VAO — 모든 attribute 버퍼가 동일한 totalVerts 크기
  s.lineVAO = gl2.createVertexArray();
  gl2.bindVertexArray(s.lineVAO);

  s.linePosB = gl2.createBuffer();
  gl2.bindBuffer(gl2.ARRAY_BUFFER, s.linePosB);
  gl2.bufferData(gl2.ARRAY_BUFFER, posArr, gl2.STATIC_DRAW);
  gl2.enableVertexAttribArray(0);
  gl2.vertexAttribPointer(0, 3, gl2.FLOAT, false, 0, 0);

  s.lineColB = gl2.createBuffer();
  gl2.bindBuffer(gl2.ARRAY_BUFFER, s.lineColB);
  gl2.bufferData(gl2.ARRAY_BUFFER, colArr, gl2.STATIC_DRAW);
  gl2.enableVertexAttribArray(1);
  gl2.vertexAttribPointer(1, 3, gl2.FLOAT, false, 0, 0);

  s.lineAlphaB = gl2.createBuffer();
  gl2.bindBuffer(gl2.ARRAY_BUFFER, s.lineAlphaB);
  gl2.bufferData(gl2.ARRAY_BUFFER, alphaArr, gl2.DYNAMIC_DRAW);
  gl2.enableVertexAttribArray(2);
  gl2.vertexAttribPointer(2, 1, gl2.FLOAT, false, 0, 0);

  gl2.bindVertexArray(null);

  // 국가 점 VAO
  var countryKeys = Object.keys(countrySet);
  var dotR = GLOBE_R * 1.008;
  var dotPos    = new Float32Array(countryKeys.length * 3);
  var dotCol    = new Float32Array(countryKeys.length * 3);
  var dotSz     = new Float32Array(countryKeys.length);
  var maxV      = Math.max.apply(null, Object.values(countrySet));
  for (var pi = 0; pi < countryKeys.length; pi++) {
    var cName = countryKeys[pi];
    var coord = COUNTRY_COORDS[cName];
    var v3 = lngLatToVec3(coord[0], coord[1], dotR);
    dotPos[pi*3]=v3[0]; dotPos[pi*3+1]=v3[1]; dotPos[pi*3+2]=v3[2];
    var tv = Math.pow(countrySet[cName]/maxV, 0.4);
    var rc = getRegionColor(cName);
    dotCol[pi*3]=rc[0]*0.5+tv*0.5; dotCol[pi*3+1]=rc[1]*0.5+tv*0.5; dotCol[pi*3+2]=rc[2]*0.5+tv*0.5;
    dotSz[pi] = 8 + tv*30;
  }

  s.dotVAO = gl2.createVertexArray();
  gl2.bindVertexArray(s.dotVAO);

  s.dotPosB = gl2.createBuffer();
  gl2.bindBuffer(gl2.ARRAY_BUFFER, s.dotPosB);
  gl2.bufferData(gl2.ARRAY_BUFFER, dotPos, gl2.STATIC_DRAW);
  gl2.enableVertexAttribArray(0);
  gl2.vertexAttribPointer(0, 3, gl2.FLOAT, false, 0, 0);

  s.dotColB = gl2.createBuffer();
  gl2.bindBuffer(gl2.ARRAY_BUFFER, s.dotColB);
  gl2.bufferData(gl2.ARRAY_BUFFER, dotCol, gl2.STATIC_DRAW);
  gl2.enableVertexAttribArray(1);
  gl2.vertexAttribPointer(1, 3, gl2.FLOAT, false, 0, 0);

  s.dotSzB = gl2.createBuffer();
  gl2.bindBuffer(gl2.ARRAY_BUFFER, s.dotSzB);
  gl2.bufferData(gl2.ARRAY_BUFFER, dotSz, gl2.STATIC_DRAW);
  gl2.enableVertexAttribArray(2);
  gl2.vertexAttribPointer(2, 1, gl2.FLOAT, false, 0, 0);

  gl2.bindVertexArray(null);
  s.dotCount = countryKeys.length;

  // 화물 박스 VAO — instanced rendering
  var numRoutes = routes.length;
  s.boxInstB = gl2.createBuffer();
  gl2.bindBuffer(gl2.ARRAY_BUFFER, s.boxInstB);
  gl2.bufferData(gl2.ARRAY_BUFFER, new Float32Array(numRoutes * 7), gl2.DYNAMIC_DRAW);

  s.boxVAO = gl2.createVertexArray();
  gl2.bindVertexArray(s.boxVAO);

  // Attribute 0: quad vertices from quadVB (per-vertex, NOT instanced)
  gl2.bindBuffer(gl2.ARRAY_BUFFER, s.quadVB);
  gl2.enableVertexAttribArray(0);
  gl2.vertexAttribPointer(0, 2, gl2.FLOAT, false, 0, 0);
  // divisor=0 (per-vertex) — this is the default, but let's be explicit
  gl2.vertexAttribDivisor(0, 0);

  // Attributes 1,2,3: instance data from boxInstB
  gl2.bindBuffer(gl2.ARRAY_BUFFER, s.boxInstB);
  gl2.enableVertexAttribArray(1);
  gl2.vertexAttribPointer(1, 3, gl2.FLOAT, false, 28, 0);
  gl2.vertexAttribDivisor(1, 1);
  gl2.enableVertexAttribArray(2);
  gl2.vertexAttribPointer(2, 3, gl2.FLOAT, false, 28, 12);
  gl2.vertexAttribDivisor(2, 1);
  gl2.enableVertexAttribArray(3);
  gl2.vertexAttribPointer(3, 1, gl2.FLOAT, false, 28, 24);
  gl2.vertexAttribDivisor(3, 1);

  gl2.bindVertexArray(null);

  s.routes           = routes;
  s.lineTotalVerts   = totalVerts;
  s.lineVertsPerRoute = VERTS;
  s.numRoutes        = numRoutes;
  s.builtScene       = true;
  console.log('Scene built: ' + numRoutes + ' routes, ' + totalVerts + ' line verts, ' + s.dotCount + ' dots');
};

s.dataLoaded = false;
s.builtScene = false;
s.tradeData  = null;

fetch(ctx.uploads['world_trade_100k.csv'])
  .then(function(r) { return r.text(); })
  .then(function(text) {
    s.tradeData  = parseCSV(text);
    s.dataLoaded = true;
    console.log('CSV loaded:', s.tradeData.length, 'rows');
  })
  .catch(function(err) { console.error('Trade data load failed:', err); });

script.render:
var gl   = ctx.gl;
var s    = ctx.state;
var W = ctx.resolution[0], H = ctx.resolution[1];
var t    = ctx.time;
var mat4 = ctx.utils.mat4;

if (!s.cam) return;

// 데이터 로드 완료 후 씬 빌드 (1회)
if (s.dataLoaded && !s.builtScene && s._buildScene) {
  s._buildScene(ctx);
  return;
}

// 카메라 거리 유니폼 적용
var camDist = ctx.uniforms.u_camera_distance ?? 14.0;
s.cam.setDistance(camDist);

var sensitivity = ctx.uniforms.u_sensitivity ?? 1.5;
s.cam.rotateSpeed = sensitivity;
s.cam.update(ctx.mouse, ctx.mousePrev, ctx.mouseDown, ctx.keys, ctx.dt);
var view = s.cam.getViewMatrix();
var proj = s.cam.getProjectionMatrix(W / H, 45, 0.1, 200);

var GR = s.GLOBE_R ?? 5.0;
var globeScale = ctx.uniforms.u_globe_scale ?? 1.0;
var rotationDeg = ctx.uniforms.u_rotation ?? 0.0;
var rotationRad = rotationDeg * Math.PI / 180.0;
var uvFlip = ctx.uniforms.u_uv_flip ?? 0.0;

var visualR = GR * globeScale;
var scaleM = mat4.fromScaling(visualR, visualR, visualR);
var rotM   = mat4.fromYRotation(rotationRad);
var globeModel = mat4.multiply(rotM, scaleM);
var vp = mat4.multiply(proj, view);
var globeMVP = mat4.multiply(vp, globeModel);

// FBO 리사이즈 체크
if (s.sceneFBO && (s.sceneFBOSize[0] !== W || s.sceneFBOSize[1] !== H)) {
  gl.deleteTexture(s.sceneFBO.colorTex);
  gl.deleteTexture(s.sceneFBO.depthTex);
  gl.deleteFramebuffer(s.sceneFBO.framebuffer);

  var fb = gl.createFramebuffer();
  gl.bindFramebuffer(gl.FRAMEBUFFER, fb);

  var colorTex = gl.createTexture();
  gl.bindTexture(gl.TEXTURE_2D, colorTex);
  gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA16F, W, H, 0, gl.RGBA, gl.HALF_FLOAT, null);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
  gl.framebufferTexture2D(gl.FRAMEBUFFER, gl.COLOR_ATTACHMENT0, gl.TEXTURE_2D, colorTex, 0);

  var depthTex = gl.createTexture();
  gl.bindTexture(gl.TEXTURE_2D, depthTex);
  gl.texImage2D(gl.TEXTURE_2D, 0, gl.DEPTH_COMPONENT24, W, H, 0, gl.DEPTH_COMPONENT, gl.UNSIGNED_INT, null);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.NEAREST);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.NEAREST);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
  gl.framebufferTexture2D(gl.FRAMEBUFFER, gl.DEPTH_ATTACHMENT, gl.TEXTURE_2D, depthTex, 0);

  gl.bindFramebuffer(gl.FRAMEBUFFER, null);
  s.sceneFBO = { framebuffer: fb, colorTex: colorTex, depthTex: depthTex, width: W, height: H };
  s.sceneFBOSize = [W, H];
}

// Pass 1: 씬을 FBO에 렌더
gl.bindFramebuffer(gl.FRAMEBUFFER, s.sceneFBO.framebuffer);
gl.viewport(0, 0, W, H);
gl.clearColor(0.0, 0.0, 0.0, 1.0);
gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
gl.enable(gl.DEPTH_TEST);
gl.depthMask(true);
gl.disable(gl.BLEND);

// 지구 렌더
if (s.globeProg && s.sphereVAO) {
  gl.useProgram(s.globeProg);
  gl.uniformMatrix4fv(s.globeLocs.mvp,   false, globeMVP);
  gl.uniformMatrix4fv(s.globeLocs.model, false, globeModel);
  gl.uniform3fv(s.globeLocs.light, [16.0, 10.0, 16.0]);

  gl.activeTexture(gl.TEXTURE0);
  gl.bindTexture(gl.TEXTURE_2D, s.earthTex);
  gl.uniform1i(s.globeLocs.uEarthTex, 0);
  gl.uniform1f(s.globeLocs.uTexLoaded, s.earthTexLoaded ? 1.0 : 0.0);
  gl.uniform1f(s.globeLocs.uUVFlip, uvFlip);

  gl.bindVertexArray(s.sphereVAO);
  gl.drawElements(gl.TRIANGLES, s.sphereIdxCount, s.sphereIdxType, 0);
  gl.bindVertexArray(null);
}

// 교역 데이터 렌더
if (s.builtScene && s.routes && s.routes.length > 0 && s.lineVAO && s.dotVAO && s.boxVAO) {
  var speed    = ctx.uniforms.u_speed ?? 1.0;
  var trailLen = ctx.uniforms.u_trail ?? 0.22;
  var ballSize = ctx.uniforms.u_ball_size ?? 0.5;
  var VERTS    = s.lineVertsPerRoute ?? 41;
  var fadeZone = 0.15;
  var numRoutes = s.routes.length;

  // Alpha & box 데이터 업데이트
  var alphaArr = new Float32Array(s.lineTotalVerts);
  for (var ai = 0; ai < s.lineTotalVerts; ai++) alphaArr[ai] = 0.08;

  var boxData  = new Float32Array(numRoutes * 7);

  for (var ri = 0; ri < numRoutes; ri++) {
    var route = s.routes[ri];
    if (route.startIdx < 0 || route.startIdx + VERTS > s.lineTotalVerts) continue;

    var boxT  = ((t * route.speed * speed + route.phase / (Math.PI * 2)) % 1.0 + 1.0) % 1.0;

    var easeFactor;
    if (boxT < fadeZone) {
      var et = boxT / fadeZone;
      easeFactor = et * et * (3.0 - 2.0 * et);
    } else if (boxT > (1.0 - fadeZone)) {
      var et2 = (1.0 - boxT) / fadeZone;
      easeFactor = et2 * et2 * (3.0 - 2.0 * et2);
    } else {
      easeFactor = 1.0;
    }

    for (var i = 0; i < VERTS; i++) {
      var lt = i / (VERTS - 1);
      var d = boxT - lt;
      if (d < 0) d += 1.0;
      var trailAlpha = (d < trailLen) ? (1.0 - d / trailLen) * 0.85 : 0.0;
      alphaArr[route.startIdx + i] = Math.max(0.08, trailAlpha * easeFactor);
    }

    var mt2 = 1.0 - boxT;
    var bx = mt2*mt2*route.p0[0] + 2*mt2*boxT*route.ctrl[0] + boxT*boxT*route.p1[0];
    var by = mt2*mt2*route.p0[1] + 2*mt2*boxT*route.ctrl[1] + boxT*boxT*route.p1[1];
    var bz = mt2*mt2*route.p0[2] + 2*mt2*boxT*route.ctrl[2] + boxT*boxT*route.p1[2];

    var baseScale = 0.06 + Math.min(0.12, Math.log10(Math.max(1, route.value)) * 0.016);
    var finalScale = baseScale * easeFactor * ballSize;

    var base = ri * 7;
    boxData[base]   = bx; boxData[base+1] = by; boxData[base+2] = bz;
    boxData[base+3] = route.col[0]; boxData[base+4] = route.col[1]; boxData[base+5] = route.col[2];
    boxData[base+6] = finalScale;
  }

  // 라인 알파 업데이트
  gl.bindBuffer(gl.ARRAY_BUFFER, s.lineAlphaB);
  gl.bufferData(gl.ARRAY_BUFFER, alphaArr, gl.DYNAMIC_DRAW);

  // 박스 인스턴스 데이터 업데이트
  gl.bindBuffer(gl.ARRAY_BUFFER, s.boxInstB);
  gl.bufferData(gl.ARRAY_BUFFER, boxData, gl.DYNAMIC_DRAW);

  gl.enable(gl.BLEND);
  gl.depthMask(false);

  // 교역 곡선 렌더 (additive)
  gl.blendFunc(gl.SRC_ALPHA, gl.ONE);
  gl.useProgram(s.lineProg);
  gl.uniformMatrix4fv(s.lineLocs.mvp, false, vp);
  gl.bindVertexArray(s.lineVAO);
  // 안전한 draw: 전체를 한번에 LINE_STRIP 대신 개별 route별로 bounds 체크
  for (var ri2 = 0; ri2 < numRoutes; ri2++) {
    var rr = s.routes[ri2];
    if (rr.startIdx >= 0 && (rr.startIdx + VERTS) <= s.lineTotalVerts) {
      gl.drawArrays(gl.LINE_STRIP, rr.startIdx, VERTS);
    }
  }
  gl.bindVertexArray(null);

  // 국가 점 렌더
  gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
  gl.depthMask(true);
  gl.useProgram(s.dotProg);
  gl.uniformMatrix4fv(s.dotLocs.mvp, false, vp);
  gl.bindVertexArray(s.dotVAO);
  if (s.dotCount > 0) {
    gl.drawArrays(gl.POINTS, 0, s.dotCount);
  }
  gl.bindVertexArray(null);

  // 화물 박스 렌더
  gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
  gl.depthMask(false);
  gl.useProgram(s.boxProg);
  gl.uniformMatrix4fv(s.boxLocs.mvp,  false, vp);
  gl.uniformMatrix4fv(s.boxLocs.view, false, view);
  gl.bindVertexArray(s.boxVAO);
  if (numRoutes > 0) {
    gl.drawArraysInstanced(gl.TRIANGLES, 0, 6, numRoutes);
  }
  gl.bindVertexArray(null);

  gl.depthMask(true);
  gl.disable(gl.BLEND);
}

// Pass 2: 대기 산란 합성
gl.bindFramebuffer(gl.FRAMEBUFFER, null);
gl.viewport(0, 0, W, H);
gl.clearColor(0.0, 0.0, 0.0, 1.0);
gl.clear(gl.COLOR_BUFFER_BIT);
gl.disable(gl.DEPTH_TEST);
gl.disable(gl.BLEND);

gl.useProgram(s.atmoProg);

gl.activeTexture(gl.TEXTURE0);
gl.bindTexture(gl.TEXTURE_2D, s.sceneFBO.colorTex);
gl.uniform1i(s.atmoLocs.uSceneColor, 0);

gl.activeTexture(gl.TEXTURE1);
gl.bindTexture(gl.TEXTURE_2D, s.sceneFBO.depthTex);
gl.uniform1i(s.atmoLocs.uSceneDepth, 1);

var invVP = mat4.invert(vp);
gl.uniformMatrix4fv(s.atmoLocs.uInvVP, false, invVP);

var camPos = s.cam.getEye();
gl.uniform3fv(s.atmoLocs.uCamPos, camPos);

var sunAngle = ctx.uniforms.u_atmo_sun_angle ?? 45.0;
var sunAngleRad = sunAngle * Math.PI / 180.0;
var sunDir = [Math.cos(sunAngleRad), 0.3, Math.sin(sunAngleRad)];
var sunLen = Math.sqrt(sunDir[0]*sunDir[0] + sunDir[1]*sunDir[1] + sunDir[2]*sunDir[2]);
sunDir[0] /= sunLen; sunDir[1] /= sunLen; sunDir[2] /= sunLen;
gl.uniform3fv(s.atmoLocs.uSunDir, sunDir);

gl.uniform1f(s.atmoLocs.uTime, t);
gl.uniform1f(s.atmoLocs.uAtmoIntensity, ctx.uniforms.u_atmo_intensity ?? 1.0);
gl.uniform1f(s.atmoLocs.uSunIntensity, ctx.uniforms.u_atmo_sun_intensity ?? 20.0);
gl.uniform1f(s.atmoLocs.uAtmoEnabled, ctx.uniforms.u_atmo_enabled ?? 1.0);
gl.uniform1f(s.atmoLocs.uGlobeR, GR);
gl.uniform1f(s.atmoLocs.uGlobeScale, globeScale);
gl.uniform1f(s.atmoLocs.uNear, 0.1);
gl.uniform1f(s.atmoLocs.uFar, 200.0);

gl.bindVertexArray(s.fsQuadVAO);
gl.drawArrays(gl.TRIANGLES, 0, 6);
gl.bindVertexArray(null);

