if (s.globeProg) gl.deleteProgram(s.globeProg);
if (s.dotProg)   gl.deleteProgram(s.dotProg);
if (s.lineProg)  gl.deleteProgram(s.lineProg);
if (s.boxProg)   gl.deleteProgram(s.boxProg);
