if (s.sceneFBO) {
  gl.deleteTexture(s.sceneFBO.colorTex);
  gl.deleteTexture(s.sceneFBO.depthTex);
  gl.deleteFramebuffer(s.sceneFBO.framebuffer);
}
[s.spherePosB, s.sphereNormB, s.sphereUVB, s.sphereIdxB,
 s.dotPosB, s.dotColB, s.dotSzB,
 s.linePosB, s.lineColB, s.lineAlphaB,
 s.quadVB, s.boxInstB, s.fsQuadBuf].forEach(function(b) { if (b) gl.deleteBuffer(b); });
[s.sphereVAO, s.dotVAO, s.lineVAO, s.boxVAO, s.fsQuadVAO].forEach(function(v) { if (v) gl.deleteVertexArray(v); });
